+#ifndef KUKA_EXTERNAL_CONTROL__KSS_EKI_COMM_CLIENT_H_
+#define KUKA_EXTERNAL_CONTROL__KSS_EKI_COMM_CLIENT_H_
+
+#include <atomic>
+#include <condition_variable>
