+#ifndef PB_BUFFER_ONLY
+  if (!stream->callback(stream, buf, 1)) PB_RETURN_ERROR(stream, "io error");
+#else
+  *buf = *(const pb_byte_t *)stream->state;
+  stream->state = (pb_byte_t *)stream->state + 1;
+#endif
+
+  stream->bytes_left--;
+
+  return true;
+}
