+        PB_RETURN_ERROR(stream, "wrong wire type");
+
+      return pb_decode_fixed32(stream, field->pData);
+
+    case PB_LTYPE_FIXED64:
+      if (wire_type != PB_WT_64BIT && wire_type != PB_WT_PACKED)
