+             * number of remaining entries. Round the division
+             * upwards. */
+            size_t remain = (substream.bytes_left - 1) / field->data_size + 1;
+            if (remain < PB_SIZE_MAX - allocated_size)
+              allocated_size += remain;
+            else
+              allocated_size += 1;
+
+            if (!allocate_field(&substream, field->pField, field->data_size, allocated_size)) {
+              status = false;
+              break;
+            }
+          }
+
+          /* Decode the array entry */
+          field->pData = *(char **)field->pField + field->data_size * (*size);
+          if (field->pData == NULL) {
+            /* Shouldn't happen, but satisfies static analyzers */
+            status = false;
+            break;
+          }
+          initialize_pointer_field(field->pData, field);
+          if (!decode_basic_field(&substream, PB_WT_PACKED, field)) {
+            status = false;
+            break;
+          }
+
+          (*size)++;
+        }
+        if (!pb_close_string_substream(stream, &substream)) return false;
+
+        return status;
+      } else {
+        /* Normal repeated field, i.e. only one item at a time. */
+        pb_size_t *size = (pb_size_t *)field->pSize;
+
+        if (*size == PB_SIZE_MAX) PB_RETURN_ERROR(stream, "too many array entries");
+
+        if (!allocate_field(stream, field->pField, field->data_size, (size_t)(*size + 1)))
+          return false;
+
+        field->pData = *(char **)field->pField + field->data_size * (*size);
+        (*size)++;
+        initialize_pointer_field(field->pData, field);
+        return decode_basic_field(stream, wire_type, field);
+      }
+
+    default:
+      PB_RETURN_ERROR(stream, "invalid field type");
+  }
+#endif
+}
+
+static bool checkreturn decode_callback_field(pb_istream_t *stream, pb_wire_type_t wire_type,
+                                              pb_field_iter_t *field) {
+  if (!field->descriptor->field_callback) return pb_skip_field(stream, wire_type);
+
+  if (wire_type == PB_WT_STRING) {
+    pb_istream_t substream;
+    size_t prev_bytes_left;
+
+    if (!pb_make_string_substream(stream, &substream)) return false;
+
+    do {
+      prev_bytes_left = substream.bytes_left;
+      if (!field->descriptor->field_callback(&substream, NULL, field)) {
+        PB_SET_ERROR(stream, substream.errmsg ? substream.errmsg : "callback failed");
+        return false;
+      }
+    } while (substream.bytes_left > 0 && substream.bytes_left < prev_bytes_left);
+
+    if (!pb_close_string_substream(stream, &substream)) return false;
+
+    return true;
+  } else {
+    /* Copy the single scalar value to stack.
+     * This is required so that we can limit the stream length,
+     * which in turn allows to use same callback for packed and
+     * not-packed fields. */
+    pb_istream_t substream;
+    pb_byte_t buffer[10];
+    size_t size = sizeof(buffer);
+
+    if (!read_raw_value(stream, wire_type, buffer, &size)) return false;
+    substream = pb_istream_from_buffer(buffer, size);
+
+    return field->descriptor->field_callback(&substream, NULL, field);
+  }
+}
+
+static bool checkreturn decode_field(pb_istream_t *stream, pb_wire_type_t wire_type,
+                                     pb_field_iter_t *field) {
+#ifdef PB_ENABLE_MALLOC
+  /* When decoding an oneof field, check if there is old data that must be
+   * released first. */
+  if (PB_HTYPE(field->type) == PB_HTYPE_ONEOF) {
+    if (!pb_release_union_field(stream, field)) return false;
+  }
+#endif
+
+  switch (PB_ATYPE(field->type)) {
+    case PB_ATYPE_STATIC:
+      return decode_static_field(stream, wire_type, field);
+
+    case PB_ATYPE_POINTER:
+      return decode_pointer_field(stream, wire_type, field);
+
+    case PB_ATYPE_CALLBACK:
+      return decode_callback_field(stream, wire_type, field);
+
+    default:
+      PB_RETURN_ERROR(stream, "invalid field type");
+  }
+}
+
+/* Default handler for extension fields. Expects to have a pb_msgdesc_t
+ * pointer in the extension->type->arg field, pointing to a message with
+ * only one field in it.  */
+static bool checkreturn default_extension_decoder(pb_istream_t *stream, pb_extension_t *extension,
+                                                  uint32_t tag, pb_wire_type_t wire_type) {
+  pb_field_iter_t iter;
+
+  if (!pb_field_iter_begin_extension(&iter, extension))
+    PB_RETURN_ERROR(stream, "invalid extension");
+
+  if (iter.tag != tag || !iter.message) return true;
+
+  extension->found = true;
+  return decode_field(stream, wire_type, &iter);
+}
+
+/* Try to decode an unknown field as an extension field. Tries each extension
+ * decoder in turn, until one of them handles the field or loop ends. */
+static bool checkreturn decode_extension(pb_istream_t *stream, uint32_t tag,
+                                         pb_wire_type_t wire_type, pb_extension_t *extension) {
+  size_t pos = stream->bytes_left;
+
+  while (extension != NULL && pos == stream->bytes_left) {
+    bool status;
+    if (extension->type->decode)
+      status = extension->type->decode(stream, extension, tag, wire_type);
+    else
+      status = default_extension_decoder(stream, extension, tag, wire_type);
+
+    if (!status) return false;
+
+    extension = extension->next;
+  }
+
+  return true;
+}
+
+/* Initialize message fields to default values, recursively */
+static bool pb_field_set_to_default(pb_field_iter_t *field) {
+  pb_type_t type;
+  type = field->type;
+
+  if (PB_LTYPE(type) == PB_LTYPE_EXTENSION) {
+    pb_extension_t *ext = *(pb_extension_t *const *)field->pData;
+    while (ext != NULL) {
+      pb_field_iter_t ext_iter;
+      if (pb_field_iter_begin_extension(&ext_iter, ext)) {
+        ext->found = false;
+        if (!pb_message_set_to_defaults(&ext_iter)) return false;
+      }
+      ext = ext->next;
+    }
+  } else if (PB_ATYPE(type) == PB_ATYPE_STATIC) {
+    bool init_data = true;
+    if (PB_HTYPE(type) == PB_HTYPE_OPTIONAL && field->pSize != NULL) {
+      /* Set has_field to false. Still initialize the optional field
+       * itself also. */
+      *(bool *)field->pSize = false;
+    } else if (PB_HTYPE(type) == PB_HTYPE_REPEATED || PB_HTYPE(type) == PB_HTYPE_ONEOF) {
+      /* REPEATED: Set array count to 0, no need to initialize contents.
+         ONEOF: Set which_field to 0. */
+      *(pb_size_t *)field->pSize = 0;
+      init_data = false;
+    }
+
+    if (init_data) {
+      if (PB_LTYPE_IS_SUBMSG(field->type) && (field->submsg_desc->default_value != NULL ||
+                                              field->submsg_desc->field_callback != NULL ||
+                                              field->submsg_desc->submsg_info[0] != NULL)) {
+        /* Initialize submessage to defaults.
+         * Only needed if it has default values
+         * or callback/submessage fields. */
+        pb_field_iter_t submsg_iter;
+        if (pb_field_iter_begin(&submsg_iter, field->submsg_desc, field->pData)) {
+          if (!pb_message_set_to_defaults(&submsg_iter)) return false;
+        }
+      } else {
+        /* Initialize to zeros */
+        memset(field->pData, 0, (size_t)field->data_size);
+      }
+    }
+  } else if (PB_ATYPE(type) == PB_ATYPE_POINTER) {
+    /* Initialize the pointer to NULL. */
+    *(void **)field->pField = NULL;
+
+    /* Initialize array count to 0. */
+    if (PB_HTYPE(type) == PB_HTYPE_REPEATED || PB_HTYPE(type) == PB_HTYPE_ONEOF) {
+      *(pb_size_t *)field->pSize = 0;
+    }
+  } else if (PB_ATYPE(type) == PB_ATYPE_CALLBACK) {
+    /* Don't overwrite callback */
+  }
+
+  return true;
+}
+
+static bool pb_message_set_to_defaults(pb_field_iter_t *iter) {
+  pb_istream_t defstream = PB_ISTREAM_EMPTY;
+  uint32_t tag = 0;
+  pb_wire_type_t wire_type = PB_WT_VARINT;
+  bool eof;
+
+  if (iter->descriptor->default_value) {
+    defstream = pb_istream_from_buffer(iter->descriptor->default_value, (size_t)-1);
+    if (!pb_decode_tag(&defstream, &wire_type, &tag, &eof)) return false;
+  }
+
+  do {
+    if (!pb_field_set_to_default(iter)) return false;
+
+    if (tag != 0 && iter->tag == tag) {
+      /* We have a default value for this field in the defstream */
+      if (!decode_field(&defstream, wire_type, iter)) return false;
+      if (!pb_decode_tag(&defstream, &wire_type, &tag, &eof)) return false;
+
+      if (iter->pSize) *(bool *)iter->pSize = false;
+    }
+  } while (pb_field_iter_next(iter));
+
+  return true;
+}
+
+/*********************
+ * Decode all fields *
+ *********************/
+
+static bool checkreturn pb_decode_inner(pb_istream_t *stream, const pb_msgdesc_t *fields,
+                                        void *dest_struct, unsigned int flags) {
+  uint32_t extension_range_start = 0;
+  pb_extension_t *extensions = NULL;
+
+  /* 'fixed_count_field' and 'fixed_count_size' track position of a repeated fixed
+   * count field. This can only handle _one_ repeated fixed count field that
+   * is unpacked and unordered among other (non repeated fixed count) fields.
+   */
+  pb_size_t fixed_count_field = PB_SIZE_MAX;
+  pb_size_t fixed_count_size = 0;
+  pb_size_t fixed_count_total_size = 0;
+
+  pb_fields_seen_t fields_seen = {{0, 0}};
+  const uint32_t allbits = ~(uint32_t)0;
+  pb_field_iter_t iter;
+
+  if (pb_field_iter_begin(&iter, fields, dest_struct)) {
+    if ((flags & PB_DECODE_NOINIT) == 0) {
+      if (!pb_message_set_to_defaults(&iter)) PB_RETURN_ERROR(stream, "failed to set defaults");
+    }
+  }
+
+  while (stream->bytes_left) {
+    uint32_t tag;
+    pb_wire_type_t wire_type;
+    bool eof;
+
+    if (!pb_decode_tag(stream, &wire_type, &tag, &eof)) {
+      if (eof)
+        break;
+      else
+        return false;
+    }
+
+    if (tag == 0) {
+      if (flags & PB_DECODE_NULLTERMINATED) {
+        break;
+      } else {
+        PB_RETURN_ERROR(stream, "zero tag");
+      }
+    }
+
+    if (!pb_field_iter_find(&iter, tag) || PB_LTYPE(iter.type) == PB_LTYPE_EXTENSION) {
+      /* No match found, check if it matches an extension. */
+      if (extension_range_start == 0) {
+        if (pb_field_iter_find_extension(&iter)) {
+          extensions = *(pb_extension_t *const *)iter.pData;
+          extension_range_start = iter.tag;
+        }
+
+        if (!extensions) {
+          extension_range_start = (uint32_t)-1;
+        }
+      }
+
+      if (tag >= extension_range_start) {
+        size_t pos = stream->bytes_left;
+
+        if (!decode_extension(stream, tag, wire_type, extensions)) return false;
+
+        if (pos != stream->bytes_left) {
+          /* The field was handled */
+          continue;
+        }
+      }
+
+      /* No match found, skip data */
+      if (!pb_skip_field(stream, wire_type)) return false;
+      continue;
+    }
+
+    /* If a repeated fixed count field was found, get size from
+     * 'fixed_count_field' as there is no counter contained in the struct.
+     */
+    if (PB_HTYPE(iter.type) == PB_HTYPE_REPEATED && iter.pSize == &iter.array_size) {
+      if (fixed_count_field != iter.index) {
+        /* If the new fixed count field does not match the previous one,
+         * check that the previous one is NULL or that it finished
+         * receiving all the expected data.
+         */
+        if (fixed_count_field != PB_SIZE_MAX && fixed_count_size != fixed_count_total_size) {
+          PB_RETURN_ERROR(stream, "wrong size for fixed count field");
+        }
+
+        fixed_count_field = iter.index;
+        fixed_count_size = 0;
+        fixed_count_total_size = iter.array_size;
+      }
+
+      iter.pSize = &fixed_count_size;
+    }
+
+    if (PB_HTYPE(iter.type) == PB_HTYPE_REQUIRED &&
+        iter.required_field_index < PB_MAX_REQUIRED_FIELDS) {
+      uint32_t tmp = ((uint32_t)1 << (iter.required_field_index & 31));
+      fields_seen.bitfield[iter.required_field_index >> 5] |= tmp;
+    }
+
+    if (!decode_field(stream, wire_type, &iter)) return false;
+  }
+
+  /* Check that all elements of the last decoded fixed count field were present. */
+  if (fixed_count_field != PB_SIZE_MAX && fixed_count_size != fixed_count_total_size) {
+    PB_RETURN_ERROR(stream, "wrong size for fixed count field");
+  }
+
+  /* Check that all required fields were present. */
+  {
+    pb_size_t req_field_count = iter.descriptor->required_field_count;
+
+    if (req_field_count > 0) {
+      pb_size_t i;
+
+      if (req_field_count > PB_MAX_REQUIRED_FIELDS) req_field_count = PB_MAX_REQUIRED_FIELDS;
+
+      /* Check the whole words */
+      for (i = 0; i < (req_field_count >> 5); i++) {
+        if (fields_seen.bitfield[i] != allbits) PB_RETURN_ERROR(stream, "missing required field");
+      }
+
+      /* Check the remaining bits (if any) */
+      if ((req_field_count & 31) != 0) {
+        if (fields_seen.bitfield[req_field_count >> 5] !=
+            (allbits >> (uint_least8_t)(32 - (req_field_count & 31)))) {
+          PB_RETURN_ERROR(stream, "missing required field");
+        }
+      }
+    }
+  }
+
+  return true;
+}
+
+bool checkreturn pb_decode_ex(pb_istream_t *stream, const pb_msgdesc_t *fields, void *dest_struct,
+                              unsigned int flags) {
+  bool status;
+
+  if ((flags & PB_DECODE_DELIMITED) == 0) {
+    status = pb_decode_inner(stream, fields, dest_struct, flags);
+  } else {
+    pb_istream_t substream;
+    if (!pb_make_string_substream(stream, &substream)) return false;
+
+    status = pb_decode_inner(&substream, fields, dest_struct, flags);
+
+    if (!pb_close_string_substream(stream, &substream)) return false;
+  }
+
+#ifdef PB_ENABLE_MALLOC
+  if (!status) pb_release(fields, dest_struct);
+#endif
+
+  return status;
+}
+
+bool checkreturn pb_decode(pb_istream_t *stream, const pb_msgdesc_t *fields, void *dest_struct) {
+  bool status;
+
+  status = pb_decode_inner(stream, fields, dest_struct, 0);
+
+#ifdef PB_ENABLE_MALLOC
+  if (!status) pb_release(fields, dest_struct);
+#endif
+
+  return status;
+}
+
+#ifdef PB_ENABLE_MALLOC
+/* Given an oneof field, if there has already been a field inside this oneof,
+ * release it before overwriting with a different one. */
+static bool pb_release_union_field(pb_istream_t *stream, pb_field_iter_t *field) {
+  pb_field_iter_t old_field = *field;
+  pb_size_t old_tag = *(pb_size_t *)field->pSize; /* Previous which_ value */
+  pb_size_t new_tag = field->tag;                 /* New which_ value */
+
+  if (old_tag == 0) return true; /* Ok, no old data in union */
+
+  if (old_tag == new_tag) return true; /* Ok, old data is of same type => merge */
+
+  /* Release old data. The find can fail if the message struct contains
+   * invalid data. */
+  if (!pb_field_iter_find(&old_field, old_tag)) PB_RETURN_ERROR(stream, "invalid union tag");
+
+  pb_release_single_field(&old_field);
+
+  if (PB_ATYPE(field->type) == PB_ATYPE_POINTER) {
+    /* Initialize the pointer to NULL to make sure it is valid
+     * even in case of error return. */
+    *(void **)field->pField = NULL;
+    field->pData = NULL;
+  }
+
+  return true;
+}
+
+static void pb_release_single_field(pb_field_iter_t *field) {
+  pb_type_t type;
+  type = field->type;
+
+  if (PB_HTYPE(type) == PB_HTYPE_ONEOF) {
+    if (*(pb_size_t *)field->pSize != field->tag)
+      return; /* This is not the current field in the union */
+  }
+
+  /* Release anything contained inside an extension or submsg.
+   * This has to be done even if the submsg itself is statically
+   * allocated. */
+  if (PB_LTYPE(type) == PB_LTYPE_EXTENSION) {
+    /* Release fields from all extensions in the linked list */
+    pb_extension_t *ext = *(pb_extension_t **)field->pData;
+    while (ext != NULL) {
+      pb_field_iter_t ext_iter;
+      if (pb_field_iter_begin_extension(&ext_iter, ext)) {
+        pb_release_single_field(&ext_iter);
+      }
+      ext = ext->next;
+    }
+  } else if (PB_LTYPE_IS_SUBMSG(type) && PB_ATYPE(type) != PB_ATYPE_CALLBACK) {
+    /* Release fields in submessage or submsg array */
+    pb_size_t count = 1;
+
+    if (PB_ATYPE(type) == PB_ATYPE_POINTER) {
+      field->pData = *(void **)field->pField;
+    } else {
+      field->pData = field->pField;
+    }
+
+    if (PB_HTYPE(type) == PB_HTYPE_REPEATED) {
+      count = *(pb_size_t *)field->pSize;
+
+      if (PB_ATYPE(type) == PB_ATYPE_STATIC && count > field->array_size) {
+        /* Protect against corrupted _count fields */
+        count = field->array_size;
+      }
+    }
+
+    if (field->pData) {
+      for (; count > 0; count--) {
+        pb_release(field->submsg_desc, field->pData);
+        field->pData = (char *)field->pData + field->data_size;
+      }
+    }
+  }
+
+  if (PB_ATYPE(type) == PB_ATYPE_POINTER) {
+    if (PB_HTYPE(type) == PB_HTYPE_REPEATED &&
+        (PB_LTYPE(type) == PB_LTYPE_STRING || PB_LTYPE(type) == PB_LTYPE_BYTES)) {
+      /* Release entries in repeated string or bytes array */
+      void **pItem = *(void ***)field->pField;
+      pb_size_t count = *(pb_size_t *)field->pSize;
+      for (; count > 0; count--) {
+        pb_free(*pItem);
+        *pItem++ = NULL;
+      }
+    }
+
+    if (PB_HTYPE(type) == PB_HTYPE_REPEATED) {
+      /* We are going to release the array, so set the size to 0 */
+      *(pb_size_t *)field->pSize = 0;
+    }
+
+    /* Release main pointer */
+    pb_free(*(void **)field->pField);
+    *(void **)field->pField = NULL;
+  }
+}
+
+void pb_release(const pb_msgdesc_t *fields, void *dest_struct) {
+  pb_field_iter_t iter;
+
+  if (!dest_struct) return; /* Ignore NULL pointers, similar to free() */
+
+  if (!pb_field_iter_begin(&iter, fields, dest_struct)) return; /* Empty message type */
+
+  do {
+    pb_release_single_field(&iter);
+  } while (pb_field_iter_next(&iter));
+}
+#else
+void pb_release(const pb_msgdesc_t *fields, void *dest_struct) {
+  /* Nothing to release without PB_ENABLE_MALLOC. */
+  PB_UNUSED(fields);
+  PB_UNUSED(dest_struct);
+}
+#endif
+
+/* Field decoders */
+
+bool pb_decode_bool(pb_istream_t *stream, bool *dest) {
+  uint32_t value;
+  if (!pb_decode_varint32(stream, &value)) return false;
+
+  *(bool *)dest = (value != 0);
+  return true;
+}
+
+bool pb_decode_svarint(pb_istream_t *stream, pb_int64_t *dest) {
+  pb_uint64_t value;
+  if (!pb_decode_varint(stream, &value)) return false;
+
+  if (value & 1)
+    *dest = (pb_int64_t)(~(value >> 1));
+  else
+    *dest = (pb_int64_t)(value >> 1);
+
+  return true;
+}
+
+bool pb_decode_fixed32(pb_istream_t *stream, void *dest) {
+  union {
+    uint32_t fixed32;
+    pb_byte_t bytes[4];
+  } u;
+
+  if (!pb_read(stream, u.bytes, 4)) return false;
+
+#if defined(PB_LITTLE_ENDIAN_8BIT) && PB_LITTLE_ENDIAN_8BIT == 1
+  /* fast path - if we know that we're on little endian, assign directly */
+  *(uint32_t *)dest = u.fixed32;
+#else
+  *(uint32_t *)dest = ((uint32_t)u.bytes[0] << 0) | ((uint32_t)u.bytes[1] << 8) |
+                      ((uint32_t)u.bytes[2] << 16) | ((uint32_t)u.bytes[3] << 24);
+#endif
+  return true;
+}
+
+#ifndef PB_WITHOUT_64BIT
+bool pb_decode_fixed64(pb_istream_t *stream, void *dest) {
+  union {
+    uint64_t fixed64;
+    pb_byte_t bytes[8];
+  } u;
+
+  if (!pb_read(stream, u.bytes, 8)) return false;
+
+#if defined(PB_LITTLE_ENDIAN_8BIT) && PB_LITTLE_ENDIAN_8BIT == 1
+  /* fast path - if we know that we're on little endian, assign directly */
+  *(uint64_t *)dest = u.fixed64;
+#else
+  *(uint64_t *)dest = ((uint64_t)u.bytes[0] << 0) | ((uint64_t)u.bytes[1] << 8) |
+                      ((uint64_t)u.bytes[2] << 16) | ((uint64_t)u.bytes[3] << 24) |
+                      ((uint64_t)u.bytes[4] << 32) | ((uint64_t)u.bytes[5] << 40) |
+                      ((uint64_t)u.bytes[6] << 48) | ((uint64_t)u.bytes[7] << 56);
+#endif
+  return true;
+}
+#endif
+
+static bool checkreturn pb_dec_bool(pb_istream_t *stream, const pb_field_iter_t *field) {
+  return pb_decode_bool(stream, (bool *)field->pData);
+}
+
+static bool checkreturn pb_dec_varint(pb_istream_t *stream, const pb_field_iter_t *field) {
+  if (PB_LTYPE(field->type) == PB_LTYPE_UVARINT) {
+    pb_uint64_t value, clamped;
+    if (!pb_decode_varint(stream, &value)) return false;
+
+    /* Cast to the proper field size, while checking for overflows */
+    if (field->data_size == sizeof(pb_uint64_t))
+      clamped = *(pb_uint64_t *)field->pData = value;
+    else if (field->data_size == sizeof(uint32_t))
+      clamped = *(uint32_t *)field->pData = (uint32_t)value;
+    else if (field->data_size == sizeof(uint_least16_t))
+      clamped = *(uint_least16_t *)field->pData = (uint_least16_t)value;
+    else if (field->data_size == sizeof(uint_least8_t))
+      clamped = *(uint_least8_t *)field->pData = (uint_least8_t)value;
+    else
+      PB_RETURN_ERROR(stream, "invalid data_size");
+
+    if (clamped != value) PB_RETURN_ERROR(stream, "integer too large");
+
+    return true;
+  } else {
+    pb_uint64_t value;
+    pb_int64_t svalue;
+    pb_int64_t clamped;
+
+    if (PB_LTYPE(field->type) == PB_LTYPE_SVARINT) {
+      if (!pb_decode_svarint(stream, &svalue)) return false;
+    } else {
