+  if (alloc_size < size) PB_RETURN_ERROR(stream, "size too large");
+
+  if (PB_ATYPE(field->type) == PB_ATYPE_POINTER) {
+#ifndef PB_ENABLE_MALLOC
+    PB_RETURN_ERROR(stream, "no malloc support");
+#else
+    if (stream->bytes_left < size) PB_RETURN_ERROR(stream, "end-of-stream");
+
+    if (!allocate_field(stream, field->pData, alloc_size, 1)) return false;
+    dest = *(pb_byte_t **)field->pData;
+#endif
+  } else {
+    if (alloc_size > field->data_size) PB_RETURN_ERROR(stream, "string overflow");
+  }
