+  if (exponent == 1024) {
+    /* Special value */
+    exponent = 128;
+    mantissa >>= 1;
+  } else {
+    if (exponent > 127) {
+      /* Too large, convert to infinity */
+      exponent = 128;
+      mantissa = 0;
+    } else if (exponent < -150) {
+      /* Too small, convert to zero */
