+      mantissa &= 0x7FFFFF;
+      mantissa >>= 1;
+    }
+  }
+
+  /* Combine fields */
+  out.i = mantissa;
+  out.i |= (uint32_t)(exponent + 127) << 23;
+  out.i |= (uint32_t)sign << 31;
+
+  *dest = out.f;
+  return true;
