+static bool checkreturn buf_write(pb_ostream_t *stream, const pb_byte_t *buf, size_t count) {
+  pb_byte_t *dest = (pb_byte_t *)stream->state;
+  stream->state = dest + count;
+
+  memcpy(dest, buf, count * sizeof(pb_byte_t));
+
+  return true;
+}
+
+pb_ostream_t pb_ostream_from_buffer(pb_byte_t *buf, size_t bufsize) {
+  pb_ostream_t stream;
+#ifdef PB_BUFFER_ONLY
+  /* In PB_BUFFER_ONLY configuration the callback pointer is just int*.
+   * NULL pointer marks a sizing field, so put a non-NULL value to mark a buffer stream.
+   */
+  static const int marker = 0;
+  stream.callback = &marker;
+#else
+  stream.callback = &buf_write;
+#endif
+  stream.state = buf;
+  stream.max_size = bufsize;
+  stream.bytes_written = 0;
+#ifndef PB_NO_ERRMSG
+  stream.errmsg = NULL;
+#endif
+  return stream;
+}
+
+bool checkreturn pb_write(pb_ostream_t *stream, const pb_byte_t *buf, size_t count) {
+  if (count > 0 && stream->callback != NULL) {
+    if (stream->bytes_written + count < stream->bytes_written ||
+        stream->bytes_written + count > stream->max_size) {
+      PB_RETURN_ERROR(stream, "stream full");
+    }
+
+#ifdef PB_BUFFER_ONLY
+    if (!buf_write(stream, buf, count)) PB_RETURN_ERROR(stream, "io error");
+#else
+    if (!stream->callback(stream, buf, count)) PB_RETURN_ERROR(stream, "io error");
+#endif
+  }
+
+  stream->bytes_written += count;
+  return true;
+}
