+#ifndef PB_ENCODE_ARRAYS_UNPACKED
+  /* We always pack arrays if the datatype allows it. */
+  if (PB_LTYPE(field->type) <= PB_LTYPE_LAST_PACKABLE) {
+    if (!pb_encode_tag(stream, PB_WT_STRING, field->tag)) return false;
