+    /* Determine the total size of packed array. */
+    if (PB_LTYPE(field->type) == PB_LTYPE_FIXED32) {
+      size = 4 * (size_t)count;
+    } else if (PB_LTYPE(field->type) == PB_LTYPE_FIXED64) {
+      size = 8 * (size_t)count;
