+static bool checkreturn buf_read(pb_istream_t *stream, pb_byte_t *buf, size_t count) {
+  const pb_byte_t *source = (const pb_byte_t *)stream->state;
+  stream->state = (pb_byte_t *)stream->state + count;
+
+  if (buf != NULL) {
+    memcpy(buf, source, count * sizeof(pb_byte_t));
+  }
+
+  return true;
+}
+
+bool checkreturn pb_read(pb_istream_t *stream, pb_byte_t *buf, size_t count) {
+  if (count == 0) return true;
+
+#ifndef PB_BUFFER_ONLY
+  if (buf == NULL && stream->callback != buf_read) {
+    /* Skip input bytes */
+    pb_byte_t tmp[16];
+    while (count > 16) {
+      if (!pb_read(stream, tmp, 16)) return false;
+
+      count -= 16;
+    }
+
+    return pb_read(stream, tmp, count);
+  }
+#endif
+
+  if (stream->bytes_left < count) PB_RETURN_ERROR(stream, "end-of-stream");
+
+#ifndef PB_BUFFER_ONLY
+  if (!stream->callback(stream, buf, count)) PB_RETURN_ERROR(stream, "io error");
+#else
+  if (!buf_read(stream, buf, count)) return false;
+#endif
+
+  if (stream->bytes_left < count)
+    stream->bytes_left = 0;
+  else
+    stream->bytes_left -= count;
+
+  return true;
+}
