+static bool checkreturn pb_decode_varint32_eof(pb_istream_t *stream, uint32_t *dest, bool *eof) {
+  pb_byte_t byte;
+  uint32_t result;
+
+  if (!pb_readbyte(stream, &byte)) {
+    if (stream->bytes_left == 0) {
+      if (eof) {
+        *eof = true;
