+        PB_RETURN_ERROR(stream, "wrong wire type");
+
+      return pb_dec_varint(stream, field);
+
+    case PB_LTYPE_FIXED32:
+      if (wire_type != PB_WT_32BIT && wire_type != PB_WT_PACKED)
+        PB_RETURN_ERROR(stream, "wrong wire type");
+
+      return pb_decode_fixed32(stream, field->pData);
+
+    case PB_LTYPE_FIXED64:
+      if (wire_type != PB_WT_64BIT && wire_type != PB_WT_PACKED)
+        PB_RETURN_ERROR(stream, "wrong wire type");
+
+#ifdef PB_CONVERT_DOUBLE_FLOAT
+      if (field->data_size == sizeof(float)) {
+        return pb_decode_double_as_float(stream, (float *)field->pData);
+      }
+#endif
+
+#ifdef PB_WITHOUT_64BIT
+      PB_RETURN_ERROR(stream, "invalid data_size");
+#else
+      return pb_decode_fixed64(stream, field->pData);
+#endif
+
+    case PB_LTYPE_BYTES:
+      if (wire_type != PB_WT_STRING) PB_RETURN_ERROR(stream, "wrong wire type");
+
+      return pb_dec_bytes(stream, field);
+
+    case PB_LTYPE_STRING:
+      if (wire_type != PB_WT_STRING) PB_RETURN_ERROR(stream, "wrong wire type");
+
+      return pb_dec_string(stream, field);
+
+    case PB_LTYPE_SUBMESSAGE:
+    case PB_LTYPE_SUBMSG_W_CB:
+      if (wire_type != PB_WT_STRING) PB_RETURN_ERROR(stream, "wrong wire type");
+
+      return pb_dec_submessage(stream, field);
+
+    case PB_LTYPE_FIXED_LENGTH_BYTES:
+      if (wire_type != PB_WT_STRING) PB_RETURN_ERROR(stream, "wrong wire type");
+
+      return pb_dec_fixed_length_bytes(stream, field);
+
+    default:
+      PB_RETURN_ERROR(stream, "invalid field type");
+  }
+}
+
+static bool checkreturn decode_static_field(pb_istream_t *stream, pb_wire_type_t wire_type,
+                                            pb_field_iter_t *field) {
+  switch (PB_HTYPE(field->type)) {
+    case PB_HTYPE_REQUIRED:
+      return decode_basic_field(stream, wire_type, field);
+
+    case PB_HTYPE_OPTIONAL:
+      if (field->pSize != NULL) *(bool *)field->pSize = true;
+      return decode_basic_field(stream, wire_type, field);
+
+    case PB_HTYPE_REPEATED:
+      if (wire_type == PB_WT_STRING && PB_LTYPE(field->type) <= PB_LTYPE_LAST_PACKABLE) {
+        /* Packed array */
+        bool status = true;
+        pb_istream_t substream;
+        pb_size_t *size = (pb_size_t *)field->pSize;
+        field->pData = (char *)field->pField + field->data_size * (*size);
+
+        if (!pb_make_string_substream(stream, &substream)) return false;
+
+        while (substream.bytes_left > 0 && *size < field->array_size) {
+          if (!decode_basic_field(&substream, PB_WT_PACKED, field)) {
+            status = false;
+            break;
+          }
+          (*size)++;
+          field->pData = (char *)field->pData + field->data_size;
+        }
+
+        if (substream.bytes_left != 0) PB_RETURN_ERROR(stream, "array overflow");
+        if (!pb_close_string_substream(stream, &substream)) return false;
+
+        return status;
+      } else {
+        /* Repeated field */
+        pb_size_t *size = (pb_size_t *)field->pSize;
+        field->pData = (char *)field->pField + field->data_size * (*size);
+
+        if ((*size)++ >= field->array_size) PB_RETURN_ERROR(stream, "array overflow");
+
+        return decode_basic_field(stream, wire_type, field);
+      }
+
+    case PB_HTYPE_ONEOF:
+      if (PB_LTYPE_IS_SUBMSG(field->type) && *(pb_size_t *)field->pSize != field->tag) {
+        /* We memset to zero so that any callbacks are set to NULL.
+         * This is because the callbacks might otherwise have values
+         * from some other union field.
+         * If callbacks are needed inside oneof field, use .proto
+         * option submsg_callback to have a separate callback function
+         * that can set the fields before submessage is decoded.
+         * pb_dec_submessage() will set any default values. */
+        memset(field->pData, 0, (size_t)field->data_size);
+
+        /* Set default values for the submessage fields. */
+        if (field->submsg_desc->default_value != NULL ||
+            field->submsg_desc->field_callback != NULL ||
+            field->submsg_desc->submsg_info[0] != NULL) {
+          pb_field_iter_t submsg_iter;
+          if (pb_field_iter_begin(&submsg_iter, field->submsg_desc, field->pData)) {
+            if (!pb_message_set_to_defaults(&submsg_iter))
+              PB_RETURN_ERROR(stream, "failed to set defaults");
+          }
+        }
+      }
+      *(pb_size_t *)field->pSize = field->tag;
+
+      return decode_basic_field(stream, wire_type, field);
+
+    default:
+      PB_RETURN_ERROR(stream, "invalid field type");
+  }
+}
+
+#ifdef PB_ENABLE_MALLOC
+/* Allocate storage for the field and store the pointer at iter->pData.
+ * array_size is the number of entries to reserve in an array.
+ * Zero size is not allowed, use pb_free() for releasing.
+ */
+static bool checkreturn allocate_field(pb_istream_t *stream, void *pData, size_t data_size,
+                                       size_t array_size) {
+  void *ptr = *(void **)pData;
+
+  if (data_size == 0 || array_size == 0) PB_RETURN_ERROR(stream, "invalid size");
+
+#ifdef __AVR__
+  /* Workaround for AVR libc bug 53284: http://savannah.nongnu.org/bugs/?53284
+   * Realloc to size of 1 byte can cause corruption of the malloc structures.
+   */
+  if (data_size == 1 && array_size == 1) {
+    data_size = 2;
+  }
+#endif
+
+  /* Check for multiplication overflows.
+   * This code avoids the costly division if the sizes are small enough.
+   * Multiplication is safe as long as only half of bits are set
+   * in either multiplicand.
+   */
+  {
+    const size_t check_limit = (size_t)1 << (sizeof(size_t) * 4);
+    if (data_size >= check_limit || array_size >= check_limit) {
+      const size_t size_max = (size_t)-1;
+      if (size_max / array_size < data_size) {
+        PB_RETURN_ERROR(stream, "size too large");
+      }
+    }
+  }
+
+  /* Allocate new or expand previous allocation */
+  /* Note: on failure the old pointer will remain in the structure,
+   * the message must be freed by caller also on error return. */
+  ptr = pb_realloc(ptr, array_size * data_size);
+  if (ptr == NULL) PB_RETURN_ERROR(stream, "realloc failed");
+
+  *(void **)pData = ptr;
+  return true;
+}
+
+/* Clear a newly allocated item in case it contains a pointer, or is a submessage. */
+static void initialize_pointer_field(void *pItem, pb_field_iter_t *field) {
+  if (PB_LTYPE(field->type) == PB_LTYPE_STRING || PB_LTYPE(field->type) == PB_LTYPE_BYTES) {
+    *(void **)pItem = NULL;
+  } else if (PB_LTYPE_IS_SUBMSG(field->type)) {
+    /* We memset to zero so that any callbacks are set to NULL.
+     * Default values will be set by pb_dec_submessage(). */
+    memset(pItem, 0, field->data_size);
+  }
+}
+#endif
+
+static bool checkreturn decode_pointer_field(pb_istream_t *stream, pb_wire_type_t wire_type,
+                                             pb_field_iter_t *field) {
+#ifndef PB_ENABLE_MALLOC
+  PB_UNUSED(wire_type);
+  PB_UNUSED(field);
+  PB_RETURN_ERROR(stream, "no malloc support");
