+  if (!pb_close_string_substream(stream, &substream)) return false;
+
+  return status;
+}
+
+static bool checkreturn pb_dec_fixed_length_bytes(pb_istream_t *stream,
+                                                  const pb_field_iter_t *field) {
+  uint32_t size;
