+bool pb_decode_double_as_float(pb_istream_t *stream, float *dest) {
+  uint_least8_t sign;
+  int exponent;
+  uint32_t mantissa;
+  uint64_t value;
+  union {
+    float f;
+    uint32_t i;
+  } out;
