+    if (!pb_encode_varint(stream, (pb_uint64_t)size)) return false;
+
+    if (stream->callback == NULL) return pb_write(stream, NULL, size); /* Just sizing.. */
+
+    /* Write the data */
+    for (i = 0; i < count; i++) {
+      if (PB_LTYPE(field->type) == PB_LTYPE_FIXED32 || PB_LTYPE(field->type) == PB_LTYPE_FIXED64) {
+        if (!pb_enc_fixed(stream, field)) return false;
+      } else {
+        if (!pb_enc_varint(stream, field)) return false;
+      }
+
+      field->pData = (char *)field->pData + field->data_size;
+    }
