+        return true;
+      }
+    } else if (PB_ATYPE(field->type) == PB_ATYPE_STATIC) {
+      /* Proto3 singular field */
+      if (pb_check_proto3_default_value(field)) return true;
+    }
+  }
+
+  if (!field->pData) {
+    if (PB_HTYPE(field->type) == PB_HTYPE_REQUIRED)
+      PB_RETURN_ERROR(stream, "missing required field");
+
+    /* Pointer field set to NULL */
+    return true;
+  }
+
+  /* Then encode field contents */
+  if (PB_ATYPE(field->type) == PB_ATYPE_CALLBACK) {
+    return encode_callback_field(stream, field);
+  } else if (PB_HTYPE(field->type) == PB_HTYPE_REPEATED) {
+    return encode_array(stream, field);
+  } else {
+    return encode_basic_field(stream, field);
+  }
+}
+
+/* Default handler for extension fields. Expects to have a pb_msgdesc_t
+ * pointer in the extension->type->arg field, pointing to a message with
+ * only one field in it.  */
+static bool checkreturn default_extension_encoder(pb_ostream_t *stream,
+                                                  const pb_extension_t *extension) {
+  pb_field_iter_t iter;
+
+  if (!pb_field_iter_begin_extension_const(&iter, extension))
+    PB_RETURN_ERROR(stream, "invalid extension");
+
+  return encode_field(stream, &iter);
+}
+
+/* Walk through all the registered extensions and give them a chance
+ * to encode themselves. */
+static bool checkreturn encode_extension_field(pb_ostream_t *stream, const pb_field_iter_t *field) {
+  const pb_extension_t *extension = *(const pb_extension_t *const *)field->pData;
+
+  while (extension) {
+    bool status;
+    if (extension->type->encode)
+      status = extension->type->encode(stream, extension);
+    else
+      status = default_extension_encoder(stream, extension);
+
+    if (!status) return false;
+
+    extension = extension->next;
+  }
+
+  return true;
+}
+
+/*********************
+ * Encode all fields *
+ *********************/
+
+bool checkreturn pb_encode(pb_ostream_t *stream, const pb_msgdesc_t *fields,
+                           const void *src_struct) {
+  pb_field_iter_t iter;
+  if (!pb_field_iter_begin_const(&iter, fields, src_struct)) return true; /* Empty message type */
+
+  do {
+    if (PB_LTYPE(iter.type) == PB_LTYPE_EXTENSION) {
+      /* Special case for the extension field placeholder */
+      if (!encode_extension_field(stream, &iter)) return false;
+    } else {
+      /* Regular field */
+      if (!encode_field(stream, &iter)) return false;
+    }
+  } while (pb_field_iter_next(&iter));
+
+  return true;
+}
+
+bool checkreturn pb_encode_ex(pb_ostream_t *stream, const pb_msgdesc_t *fields,
+                              const void *src_struct, unsigned int flags) {
+  if ((flags & PB_ENCODE_DELIMITED) != 0) {
+    return pb_encode_submessage(stream, fields, src_struct);
+  } else if ((flags & PB_ENCODE_NULLTERMINATED) != 0) {
+    const pb_byte_t zero = 0;
+
+    if (!pb_encode(stream, fields, src_struct)) return false;
+
+    return pb_write(stream, &zero, 1);
+  } else {
+    return pb_encode(stream, fields, src_struct);
+  }
+}
+
+bool pb_get_encoded_size(size_t *size, const pb_msgdesc_t *fields, const void *src_struct) {
+  pb_ostream_t stream = PB_OSTREAM_SIZING;
+
+  if (!pb_encode(&stream, fields, src_struct)) return false;
+
+  *size = stream.bytes_written;
+  return true;
+}
+
+/********************
+ * Helper functions *
+ ********************/
+
+/* This function avoids 64-bit shifts as they are quite slow on many platforms. */
+static bool checkreturn pb_encode_varint_32(pb_ostream_t *stream, uint32_t low, uint32_t high) {
+  size_t i = 0;
+  pb_byte_t buffer[10];
+  pb_byte_t byte = (pb_byte_t)(low & 0x7F);
+  low >>= 7;
+
+  while (i < 4 && (low != 0 || high != 0)) {
+    byte |= 0x80;
+    buffer[i++] = byte;
+    byte = (pb_byte_t)(low & 0x7F);
+    low >>= 7;
+  }
+
+  if (high) {
+    byte = (pb_byte_t)(byte | ((high & 0x07) << 4));
+    high >>= 3;
+
+    while (high) {
+      byte |= 0x80;
+      buffer[i++] = byte;
+      byte = (pb_byte_t)(high & 0x7F);
+      high >>= 7;
+    }
+  }
+
+  buffer[i++] = byte;
+
+  return pb_write(stream, buffer, i);
+}
+
+bool checkreturn pb_encode_varint(pb_ostream_t *stream, pb_uint64_t value) {
+  if (value <= 0x7F) {
+    /* Fast path: single byte */
+    pb_byte_t byte = (pb_byte_t)value;
+    return pb_write(stream, &byte, 1);
+  } else {
+#ifdef PB_WITHOUT_64BIT
+    return pb_encode_varint_32(stream, value, 0);
+#else
+    return pb_encode_varint_32(stream, (uint32_t)value, (uint32_t)(value >> 32));
+#endif
+  }
+}
+
+bool checkreturn pb_encode_svarint(pb_ostream_t *stream, pb_int64_t value) {
+  pb_uint64_t zigzagged;
+  pb_uint64_t mask = ((pb_uint64_t)-1) >> 1; /* Satisfy clang -fsanitize=integer */
+  if (value < 0)
+    zigzagged = ~(((pb_uint64_t)value & mask) << 1);
+  else
+    zigzagged = (pb_uint64_t)value << 1;
+
+  return pb_encode_varint(stream, zigzagged);
+}
+
+bool checkreturn pb_encode_fixed32(pb_ostream_t *stream, const void *value) {
+#if defined(PB_LITTLE_ENDIAN_8BIT) && PB_LITTLE_ENDIAN_8BIT == 1
+  /* Fast path if we know that we're on little endian */
+  return pb_write(stream, (const pb_byte_t *)value, 4);
+#else
+  uint32_t val = *(const uint32_t *)value;
+  pb_byte_t bytes[4];
+  bytes[0] = (pb_byte_t)(val & 0xFF);
+  bytes[1] = (pb_byte_t)((val >> 8) & 0xFF);
+  bytes[2] = (pb_byte_t)((val >> 16) & 0xFF);
+  bytes[3] = (pb_byte_t)((val >> 24) & 0xFF);
+  return pb_write(stream, bytes, 4);
+#endif
+}
+
+#ifndef PB_WITHOUT_64BIT
+bool checkreturn pb_encode_fixed64(pb_ostream_t *stream, const void *value) {
+#if defined(PB_LITTLE_ENDIAN_8BIT) && PB_LITTLE_ENDIAN_8BIT == 1
+  /* Fast path if we know that we're on little endian */
+  return pb_write(stream, (const pb_byte_t *)value, 8);
+#else
+  uint64_t val = *(const uint64_t *)value;
+  pb_byte_t bytes[8];
+  bytes[0] = (pb_byte_t)(val & 0xFF);
+  bytes[1] = (pb_byte_t)((val >> 8) & 0xFF);
+  bytes[2] = (pb_byte_t)((val >> 16) & 0xFF);
+  bytes[3] = (pb_byte_t)((val >> 24) & 0xFF);
+  bytes[4] = (pb_byte_t)((val >> 32) & 0xFF);
+  bytes[5] = (pb_byte_t)((val >> 40) & 0xFF);
+  bytes[6] = (pb_byte_t)((val >> 48) & 0xFF);
+  bytes[7] = (pb_byte_t)((val >> 56) & 0xFF);
+  return pb_write(stream, bytes, 8);
+#endif
+}
+#endif
+
+bool checkreturn pb_encode_tag(pb_ostream_t *stream, pb_wire_type_t wiretype,
+                               uint32_t field_number) {
+  pb_uint64_t tag = ((pb_uint64_t)field_number << 3) | wiretype;
+  return pb_encode_varint(stream, tag);
+}
+
+bool pb_encode_tag_for_field(pb_ostream_t *stream, const pb_field_iter_t *field) {
+  pb_wire_type_t wiretype;
+  switch (PB_LTYPE(field->type)) {
+    case PB_LTYPE_BOOL:
+    case PB_LTYPE_VARINT:
+    case PB_LTYPE_UVARINT:
+    case PB_LTYPE_SVARINT:
+      wiretype = PB_WT_VARINT;
+      break;
+
+    case PB_LTYPE_FIXED32:
+      wiretype = PB_WT_32BIT;
+      break;
+
+    case PB_LTYPE_FIXED64:
+      wiretype = PB_WT_64BIT;
+      break;
+
+    case PB_LTYPE_BYTES:
+    case PB_LTYPE_STRING:
+    case PB_LTYPE_SUBMESSAGE:
+    case PB_LTYPE_SUBMSG_W_CB:
+    case PB_LTYPE_FIXED_LENGTH_BYTES:
+      wiretype = PB_WT_STRING;
+      break;
+
+    default:
+      PB_RETURN_ERROR(stream, "invalid field type");
+  }
+
+  return pb_encode_tag(stream, wiretype, field->tag);
+}
+
+bool checkreturn pb_encode_string(pb_ostream_t *stream, const pb_byte_t *buffer, size_t size) {
+  if (!pb_encode_varint(stream, (pb_uint64_t)size)) return false;
+
+  return pb_write(stream, buffer, size);
+}
+
+bool checkreturn pb_encode_submessage(pb_ostream_t *stream, const pb_msgdesc_t *fields,
+                                      const void *src_struct) {
+  /* First calculate the message size using a non-writing substream. */
+  pb_ostream_t substream = PB_OSTREAM_SIZING;
+  size_t size;
+  bool status;
+
+  if (!pb_encode(&substream, fields, src_struct)) {
+#ifndef PB_NO_ERRMSG
+    stream->errmsg = substream.errmsg;
+#endif
+    return false;
+  }
+
+  size = substream.bytes_written;
+
+  if (!pb_encode_varint(stream, (pb_uint64_t)size)) return false;
+
+  if (stream->callback == NULL) return pb_write(stream, NULL, size); /* Just sizing */
+
+  if (stream->bytes_written + size > stream->max_size) PB_RETURN_ERROR(stream, "stream full");
+
+  /* Use a substream to verify that a callback doesn't write more than
+   * what it did the first time. */
+  substream.callback = stream->callback;
+  substream.state = stream->state;
+  substream.max_size = size;
+  substream.bytes_written = 0;
+#ifndef PB_NO_ERRMSG
+  substream.errmsg = NULL;
+#endif
+
+  status = pb_encode(&substream, fields, src_struct);
+
+  stream->bytes_written += substream.bytes_written;
+  stream->state = substream.state;
+#ifndef PB_NO_ERRMSG
+  stream->errmsg = substream.errmsg;
+#endif
+
+  if (substream.bytes_written != size) PB_RETURN_ERROR(stream, "submsg size changed");
+
+  return status;
+}
+
+/* Field encoders */
+
+static bool checkreturn pb_enc_bool(pb_ostream_t *stream, const pb_field_iter_t *field) {
+  uint32_t value = safe_read_bool(field->pData) ? 1 : 0;
+  PB_UNUSED(field);
+  return pb_encode_varint(stream, value);
+}
+
+static bool checkreturn pb_enc_varint(pb_ostream_t *stream, const pb_field_iter_t *field) {
+  if (PB_LTYPE(field->type) == PB_LTYPE_UVARINT) {
+    /* Perform unsigned integer extension */
+    pb_uint64_t value = 0;
+
+    if (field->data_size == sizeof(uint_least8_t))
+      value = *(const uint_least8_t *)field->pData;
+    else if (field->data_size == sizeof(uint_least16_t))
+      value = *(const uint_least16_t *)field->pData;
+    else if (field->data_size == sizeof(uint32_t))
+      value = *(const uint32_t *)field->pData;
+    else if (field->data_size == sizeof(pb_uint64_t))
+      value = *(const pb_uint64_t *)field->pData;
+    else
+      PB_RETURN_ERROR(stream, "invalid data_size");
+
+    return pb_encode_varint(stream, value);
+  } else {
+    /* Perform signed integer extension */
+    pb_int64_t value = 0;
+
+    if (field->data_size == sizeof(int_least8_t))
+      value = *(const int_least8_t *)field->pData;
+    else if (field->data_size == sizeof(int_least16_t))
+      value = *(const int_least16_t *)field->pData;
+    else if (field->data_size == sizeof(int32_t))
+      value = *(const int32_t *)field->pData;
+    else if (field->data_size == sizeof(pb_int64_t))
+      value = *(const pb_int64_t *)field->pData;
+    else
+      PB_RETURN_ERROR(stream, "invalid data_size");
+
+    if (PB_LTYPE(field->type) == PB_LTYPE_SVARINT) return pb_encode_svarint(stream, value);
+#ifdef PB_WITHOUT_64BIT
+    else if (value < 0)
+      return pb_encode_varint_32(stream, (uint32_t)value, (uint32_t)-1);
+#endif
+    else
+      return pb_encode_varint(stream, (pb_uint64_t)value);
+  }
+}
+
+static bool checkreturn pb_enc_fixed(pb_ostream_t *stream, const pb_field_iter_t *field) {
+#ifdef PB_CONVERT_DOUBLE_FLOAT
+  if (field->data_size == sizeof(float) && PB_LTYPE(field->type) == PB_LTYPE_FIXED64) {
+    return pb_encode_float_as_double(stream, *(float *)field->pData);
+  }
+#endif
+
+  if (field->data_size == sizeof(uint32_t)) {
+    return pb_encode_fixed32(stream, field->pData);
+  }
+#ifndef PB_WITHOUT_64BIT
+  else if (field->data_size == sizeof(uint64_t)) {
+    return pb_encode_fixed64(stream, field->pData);
+  }
+#endif
+  else {
+    PB_RETURN_ERROR(stream, "invalid data_size");
+  }
+}
+
+static bool checkreturn pb_enc_bytes(pb_ostream_t *stream, const pb_field_iter_t *field) {
+  const pb_bytes_array_t *bytes = NULL;
+
+  bytes = (const pb_bytes_array_t *)field->pData;
+
+  if (bytes == NULL) {
+    /* Treat null pointer as an empty bytes field */
+    return pb_encode_string(stream, NULL, 0);
+  }
+
+  if (PB_ATYPE(field->type) == PB_ATYPE_STATIC &&
+      bytes->size > field->data_size - offsetof(pb_bytes_array_t, bytes)) {
+    PB_RETURN_ERROR(stream, "bytes size exceeded");
+  }
+
+  return pb_encode_string(stream, bytes->bytes, (size_t)bytes->size);
+}
+
+static bool checkreturn pb_enc_string(pb_ostream_t *stream, const pb_field_iter_t *field) {
+  size_t size = 0;
+  size_t max_size = (size_t)field->data_size;
+  const char *str = (const char *)field->pData;
+
+  if (PB_ATYPE(field->type) == PB_ATYPE_POINTER) {
+    max_size = (size_t)-1;
+  } else {
+    /* pb_dec_string() assumes string fields end with a null
+     * terminator when the type isn't PB_ATYPE_POINTER, so we
+     * shouldn't allow more than max-1 bytes to be written to
+     * allow space for the null terminator.
+     */
+    if (max_size == 0) PB_RETURN_ERROR(stream, "zero-length string");
+
+    max_size -= 1;
+  }
+
+  if (str == NULL) {
+    size = 0; /* Treat null pointer as an empty string */
+  } else {
+    const char *p = str;
+
+    /* strnlen() is not always available, so just use a loop */
+    while (size < max_size && *p != '\0') {
+      size++;
+      p++;
+    }
+
+    if (*p != '\0') {
+      PB_RETURN_ERROR(stream, "unterminated string");
+    }
+  }
+
+#ifdef PB_VALIDATE_UTF8
+  if (!pb_validate_utf8(str)) PB_RETURN_ERROR(stream, "invalid utf8");
+#endif
+
+  return pb_encode_string(stream, (const pb_byte_t *)str, size);
+}
+
+static bool checkreturn pb_enc_submessage(pb_ostream_t *stream, const pb_field_iter_t *field) {
+  if (field->submsg_desc == NULL) PB_RETURN_ERROR(stream, "invalid field descriptor");
+
+  if (PB_LTYPE(field->type) == PB_LTYPE_SUBMSG_W_CB && field->pSize != NULL) {
+    /* Message callback is stored right before pSize. */
+    pb_callback_t *callback = (pb_callback_t *)field->pSize - 1;
+    if (callback->funcs.encode) {
+      if (!callback->funcs.encode(stream, field, &callback->arg)) return false;
+    }
+  }
+
+  return pb_encode_submessage(stream, field->submsg_desc, field->pData);
+}
+
+static bool checkreturn pb_enc_fixed_length_bytes(pb_ostream_t *stream,
+                                                  const pb_field_iter_t *field) {
+  return pb_encode_string(stream, (const pb_byte_t *)field->pData, (size_t)field->data_size);
+}
+
+#ifdef PB_CONVERT_DOUBLE_FLOAT
+bool pb_encode_float_as_double(pb_ostream_t *stream, float value) {
+  union {
+    float f;
+    uint32_t i;
+  } in;
+  uint_least8_t sign;
+  int exponent;
+  uint64_t mantissa;
+
+  in.f = value;
+
+  /* Decompose input value */
+  sign = (uint_least8_t)((in.i >> 31) & 1);
+  exponent = (int)((in.i >> 23) & 0xFF) - 127;
+  mantissa = in.i & 0x7FFFFF;
+
+  if (exponent == 128) {
+    /* Special value (NaN etc.) */
+    exponent = 1024;
+  } else if (exponent == -127) {
+    if (!mantissa) {
+      /* Zero */
+      exponent = -1023;
+    } else {
+      /* Denormalized */
+      mantissa <<= 1;
+      while (!(mantissa & 0x800000)) {
+        mantissa <<= 1;
+        exponent--;
+      }
+      mantissa &= 0x7FFFFF;
+    }
+  }
+
+  /* Combine fields */
+  mantissa <<= 29;
+  mantissa |= (uint64_t)(exponent + 1023) << 52;
+  mantissa |= (uint64_t)sign << 63;
+
+  return pb_encode_fixed64(stream, &mantissa);
+}
+#endif

